import React from 'react';
import styled from 'styled-components';
import { useTheme } from '../context/ThemeContext';
import { FontAwesomeIcon } from '@fortawesome/react-fontawesome';
import { faLightbulb, faUsers, faRocket } from '@fortawesome/free-solid-svg-icons';

const MissionSection = styled.section`
  padding: 100px 20px;
  background: ${props => props.theme.background};
  transition: all 0.3s ease;
`;

const Container = styled.div`
  max-width: 1200px;
  margin: 0 auto;
`;

const Title = styled.h2`
  text-align: center;
  color: ${props => props.theme.primary};
  font-size: 2.5rem;
  margin-bottom: 50px;
  position: relative;

  &::after {
    content: '';
    position: absolute;
    bottom: -10px;
    left: 50%;
    transform: translateX(-50%);
    width: 100px;
    height: 3px;
    background: ${props => props.theme.primary};
    transition: all 0.3s ease;
  }
`;

const CardGrid = styled.div`
  display: grid;
  grid-template-columns: repeat(auto-fit, minmax(300px, 1fr));
  gap: 30px;
  padding: 20px;
`;

const Card = styled.div`
  background: ${props => props.theme.cardBackground};
  border: 1px solid ${props => props.theme.cardBorder};
  border-radius: 15px;
  padding: 30px;
  text-align: center;
  transition: all 0.3s ease;
  
  .icon {
    font-size: 2.5rem;
    color: ${props => props.theme.primary};
    margin-bottom: 20px;
    transition: all 0.3s ease;
  }

  h3 {
    color: ${props => props.theme.primary};
    margin-bottom: 15px;
    font-size: 1.5rem;
  }

  p {
    color: ${props => props.theme.text};
    line-height: 1.6;
  }

  &:hover {
    transform: translateY(-5px);
    box-shadow: 0 5px 15px ${props => props.theme.shadowColor};

    .icon {
      transform: scale(1.1);
    }
  }
`;

const Mission = () => {
  const { theme } = useTheme();

  const missions = [
    {
      icon: faLightbulb,
      title: "Innovation",
      description: "Fostering creative thinking and innovative solutions in technology"
    },
    {
      icon: faUsers,
      title: "Collaboration",
      description: "Building a community of passionate tech enthusiasts"
    },
    {
      icon: faRocket,
      title: "Growth",
      description: "Empowering students to reach their full potential in tech"
    }
  ];

  return (
    <MissionSection theme={theme}>
      <Container>
        <Title theme={theme}>Our Mission</Title>
        <CardGrid>
          {missions.map((mission, index) => (
            <Card key={index} theme={theme}>
              <FontAwesomeIcon icon={mission.icon} className="icon" />
              <h3>{mission.title}</h3>
              <p>{mission.description}</p>
            </Card>
          ))}
        </CardGrid>
      </Container>
    </MissionSection>
  );
};

export default Mission;
